1	interface QuoteStep {
2	  op: "quote";
3	  items: { type: string }[];
4	}
5	
6	interface Scenario {
7	  customer: { yearsWithMHPCO: number };
8	  steps: QuoteStep[];
9	}
10	
11	const BASE_PREMIUM: Record<string, number> = {
12	  amulet: 60,
13	  staff: 80,
14	  potion: 40,
15	};
16	
17	const FIRST_INSURANCE_RATE = 0.1;
18	const PROCESSING_FEE = 5;
19	
20	const quotePremium = (step: QuoteStep): number => {
21	  const policyBase = step.items.reduce(
22	    (sum, item) => sum + BASE_PREMIUM[item.type],
23	    0,
24	  );
25	  const firstInsurance = policyBase * FIRST_INSURANCE_RATE;
26	  return Math.ceil(policyBase + firstInsurance + PROCESSING_FEE);
27	};
28	
29	export const runScenario = (scenario: Scenario): { results: { premium: number }[] } => {
30	  return {
31	    results: scenario.steps.map((step) => ({ premium: quotePremium(step) })),
32	  };
33	};
